const json = $input.first().json;
const question = 
  json.body?.question ??
  json.body?.message ??
  json.question ??
  json.chatInput ??
  json.input ??
  json.message;

return [{ json: { question } }];

const raw = $json.output ?? $json;
const needs_db = raw.needs_db !== false; // default true
if (!needs_db) {
  return [{ json: { analysis_type: 'followup', needs_db: false,
    domains: [], time_range_days: 0, event_hint: null,
    offset_days: [-1,0,1], inverse_lookup: false, metric_hint: null } }];
}


const domains = Array.isArray(raw.domains) ? raw.domains : ['overall'];
const analysisType = typeof raw.analysis_type === 'string' ? raw.analysis_type : 'summary';
let timeRange = (raw.time_range_days === null || raw.time_range_days === undefined) ? 30 : Number(raw.time_range_days);
const eventHint = (typeof raw.event_hint === 'string' && raw.event_hint.trim() !== '') ? raw.event_hint.toLowerCase().trim() : null;
const inverseLookup = raw.inverse_lookup === true;
const metricHint = (typeof raw.metric_hint === 'string' && raw.metric_hint.trim() !== '') ? raw.metric_hint.toLowerCase().trim() : null;

let offsetDays = [-1, 0, 1];
if (Array.isArray(raw.offset_days) && raw.offset_days.length > 0) {
  offsetDays = raw.offset_days.map(Number).filter(n => !isNaN(n) && n >= -2 && n <= 2);
}

const isCycle = analysisType === 'cycle_analysis';
const isEvent = !isCycle && (analysisType === 'event_pattern' || (domains.includes('tags') && eventHint));
const finalAnalysisType = isEvent ? 'event_pattern' : analysisType;
const finalDomains = isEvent ? Array.from(new Set([...domains, 'tags'])) : domains;

if (isEvent) {
  timeRange = 0;
  if (!inverseLookup && !eventHint) throw new Error('event_pattern requires event_hint or inverse_lookup=true with metric_hint');
  if (inverseLookup && !metricHint) throw new Error('inverse_lookup requires metric_hint');
}

if (!isEvent && (Number.isNaN(timeRange) || timeRange <= 0)) timeRange = 30;

return [{ json: { analysis_type: finalAnalysisType, domains: finalDomains, time_range_days: timeRange, event_hint: eventHint, offset_days: offsetDays, inverse_lookup: inverseLookup, metric_hint: metricHint } }];

// Context builder — dane zagregowane przez SQL
// UWAGA o kolumnach w event_pattern / summary:
//   average_hrv      = rzeczywiste HRV w milisekundach (z oura_sleep)
//   lowest_heart_rate = rzeczywiste RHR w bpm (z oura_sleep)
//   hrv_balance      = score 1-100 (contributor, z oura_daily_readiness)
//   resting_heart_rate = score 1-100 (contributor, z oura_daily_readiness)
//   stress_high_min / recovery_high_min = minuty (już przeliczone z sekund)

const normalizer = $('Normalizer').first().json;
const question = $('Normalize question').first().json.question;
const analysisType = normalizer.analysis_type;

// Helper: parsuj today_metrics z UNION ALL event_pattern / inverse_lookup
function parseTodayMetrics(rows) {
  const row = rows.find(r => r.result_type === 'today_metrics');
  if (!row) return null;
  // label format: "2026-04-09|cycle_day=22|phase=luteal|is_period=false"
  const parts = Object.fromEntries(
    row.label.split('|').slice(1).map(p => p.split('='))
  );
  return {
    date: row.label.split('|')[0],
    cycle_day: parts.cycle_day ? Number(parts.cycle_day) : null,
    cycle_phase: parts.phase || null,
    is_period: parts.is_period === 'true',
    readiness_score: row.readiness_score,
    hrv_ms: row.average_hrv,          // RZECZYWISTE ms
    rhr_bpm: row.lowest_heart_rate,   // RZECZYWISTE bpm
    hrv_balance_score: row.hrv_balance,
    sleep_efficiency: row.sleep_efficiency,
    sleep_hours: row.rem_sleep ? (row.rem_sleep / 60).toFixed(1) : null,
    restless_periods: row.restless_periods,
    temperature_deviation: row.temperature_deviation,
    steps: row.steps,
    stress_high_min: row.stress_high_min,
    recovery_high_min: row.recovery_high_min,
    active_calories: row.active_calories
  };
}

// Helper: parsuj workout_ctx
function parseWorkouts(rows) {
  return rows
    .filter(r => r.result_type === 'workout_ctx')
    .map(r => {
      const parts = r.label.split('|');
      const activity = parts[0];
      const intensity = parts[1] || '?';
      const offsetStr = (parts[2] || 'offset=0').split('=')[1];
      const offset = Number(offsetStr);
      return {
        activity, intensity, offset_days: offset,
        n_events: r.n,
        avg_calories: r.sleep_score,
        avg_distance_m: r.deep_sleep
      };
    });
}

let context = {
  question,
  analysis_type: analysisType,
  domains: normalizer.domains,
  time_range_days: normalizer.time_range_days,
  event_hint: normalizer.event_hint,
  offset_days: normalizer.offset_days,
  inverse_lookup: normalizer.inverse_lookup,
  metric_hint: normalizer.metric_hint,
  data: {}
};

if (analysisType === 'event_pattern') {
  if (normalizer.inverse_lookup) {
    const rows = $('Inverse lookup query').all().map(i => i.json);
    context.data.inverse_results = rows;
    context.data.metric_analysed = normalizer.metric_hint;
    context.data.n_tag_types = rows.length;
  } else {
    const rows = $('Event pattern query').all().map(i => i.json);
    context.data.offset_averages = rows.filter(r => r.result_type === 'offset_avg');
    context.data.baseline = rows.find(r => r.result_type === 'baseline') || null;
    context.data.co_occurring_tags = rows.filter(r => r.result_type === 'co_tag');
    context.data.cycle_phase_summary = rows.filter(r => r.result_type === 'cycle_ctx');
    context.data.events_found = rows.filter(r => r.result_type === 'event_meta');
    context.data.n_events = context.data.events_found.reduce((s, r) => s + (r.n || 0), 0);
    context.data.today = parseTodayMetrics(rows);
    context.data.workouts_around_events = parseWorkouts(rows);

    // Oblicz delta vs baseline
    const baseline = context.data.baseline;
    const metrics = ['sleep_score','deep_sleep','sleep_efficiency','rem_sleep','total_sleep',
      'readiness_score','temperature_deviation','hrv_balance','resting_heart_rate','recovery_index',
      'activity_score','steps','stress_high_min','recovery_high_min','average_hrv','lowest_heart_rate'];
    if (baseline) {
      context.data.deltas_vs_baseline = {};
      for (const row of context.data.offset_averages) {
        const d = {};
        for (const m of metrics) {
          if (row[m] != null && baseline[m] != null) {
            d[m] = Math.round((Number(row[m]) - Number(baseline[m])) * 10) / 10;
          }
        }
        context.data.deltas_vs_baseline[row.label] = d;
      }
    }
  }
} else if (analysisType === 'trend') {
  const rows = $('Trend query').all().map(i => i.json);
  context.data.daily_rows = rows;
  context.data.n_days = rows.length;
  context.data.date_range = rows.length > 0 ? { from: rows[0].day, to: rows[rows.length-1].day } : null;
  // today from last row if it matches CURRENT_DATE
  const today = rows[rows.length - 1];
  if (today) {
    context.data.today = {
      date: today.day,
      cycle_day: today.cycle_day,
      cycle_phase: today.cycle_phase,
      hrv_ms: today.average_hrv,
      rhr_bpm: today.lowest_heart_rate,
      stress_high_min: today.stress_high_min,
      workout_count: today.workout_count,
      workout_types: today.workout_types
    };
  }
} else if (analysisType === 'summary') {
  const rows = $('Summary query').all().map(i => i.json);
  context.data.averages = rows.find(r => r.record_type === 'averages') || null;
  context.data.daily_rows = rows.filter(r => r.record_type === 'daily');
  context.data.top_tags = rows.filter(r => r.record_type === 'tag');
  context.data.n_days = context.data.daily_rows.length;
  // today = last daily row
  const todayRow = context.data.daily_rows[context.data.daily_rows.length - 1];
  if (todayRow) {
    context.data.today = {
      date: todayRow.day,
      cycle_day: todayRow.cycle_day,
      cycle_phase: todayRow.cycle_phase,
      hrv_ms: todayRow.average_hrv,
      rhr_bpm: todayRow.lowest_heart_rate,
      stress_high_min: todayRow.stress_high_min,
      workout_count: todayRow.workout_count,
      workout_types: todayRow.workout_types
    };
  }
} else if (analysisType === 'cycle_analysis') {
  const rows = $('Cycle analysis query').all().map(i => i.json);
  context.data.cycle_day_stats = rows.filter(r => r.result_type === 'cycle_day_stats').map(r => JSON.parse(r.data));
  context.data.phase_summary = rows.filter(r => r.result_type === 'phase_summary').map(r => JSON.parse(r.data));
  context.data.current_cycle = rows.find(r => r.result_type === 'current_cycle')
    ? JSON.parse(rows.find(r => r.result_type === 'current_cycle').data) : null;
  // today from current_cycle
  if (context.data.current_cycle) {
    const cc = context.data.current_cycle;
    context.data.today = {
      cycle_day: cc.today_cycle_day,
      cycle_phase: cc.today_phase,
      is_period: cc.today_is_period,
      hrv_ms: cc.today_hrv_ms,
      rhr_bpm: cc.today_rhr_bpm,
      temperature_deviation: cc.today_temp_deviation,
      historical_migraine_pct_this_cycle_day: cc.today_historical_migraine_pct
    };
  }
}

// Inject conversation history
const conversationHistory = $('Load History').first().json.conversationHistory ?? [];
context.conversation_history = conversationHistory;
return [{ json: context }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversationHistory) {
  staticData.conversationHistory = [];
}
const question = $input.first().json.body?.question ?? $input.first().json.question;

return [{ json: { 
  conversationHistory: staticData.conversationHistory,
  question: question
}}];

const staticData = $getWorkflowStaticData('global');
const history = staticData.conversationHistory || [];

const question = $('Load History').first().json.question;
const analysisType = (() => {
  try { return $('Normalizer').first().json.analysis_type; } catch(e) { return 'followup'; }
})();

// Pobierz odpowiedź AI Analyst
const aiOutput = $input.first().json;
const reply = aiOutput.output ?? aiOutput.text ?? JSON.stringify(aiOutput);

// Zapisz turę
history.push({ role: 'user', content: question });
history.push({ role: 'assistant', content: reply });

// Ogranicz do ostatnich 10 tur (20 wiadomości)
const MAX_MESSAGES = 20;
if (history.length > MAX_MESSAGES) {
  history.splice(0, history.length - MAX_MESSAGES);
}

staticData.conversationHistory = history;

return [{ json: { reply, analysis_type: analysisType } }];

const question = $('Load History').first().json.question;
const history = $('Load History').first().json.conversationHistory;

// Brak nowych danych z DB — tylko pytanie + historia
const context = {
  question,
  analysis_type: 'followup',
  note: 'Follow-up question — no new database query. Use conversation history for context.',
  data: {}
};

return [{ json: context }];

const staticData = $getWorkflowStaticData('global');
staticData.conversationHistory = [];
return [{ json: { status: "History cleared" } }];
